pub mod calldata;

use anyhow::Result;
use ethers::providers::Middleware;
use ethers::types::{Address, TransactionRequest, U256};
use std::str::FromStr;

use crate::logger::{lg, lr, ly};
use crate::rpc::{execute_tx, get_fee_params, wait_receipt, Client};

const CHECKIN_CONTRACT: &str = "0x856b799345Eb20F74c1e0C5ec09ec41bEce2078c";
const DEPLOY_SIMPLE: &str = "0x2A696Ec75C8035C24185d9d88651735D64dc3249";
const DEPLOY_ERC20: &str = "0xB5239102d04128d6e1F75512A42DbfbAd5D601F5";
const DEPLOY_ERC721: &str = "0xb29534eB64ccC743665Ca997DF28016C00A7d105";
const FEE_RECEIVER: &str = "0xa0f14ec7dcecbb4bced362fdf1802a39eafcd02f";
const CHECKIN_VALUE: u64 = 10_000_000_000_000_000;

const SIMPLE_BYTECODE: &str = "";

const ERC20_BYTECODE: &str = "";

const ERC721_BYTECODE: &str = "";

async fn refresh_nonce(client: &Client, fallback: U256) -> U256 {
    client
        .get_transaction_count(client.address(), None)
        .await
        .unwrap_or(fallback)
}

async fn can_checkin_onchain(client: &Client) -> bool {
    let contract: Address = CHECKIN_CONTRACT.parse().unwrap();
    let tx = TransactionRequest::new()
        .from(client.address())
        .to(contract)
        .data(calldata::build_checkin())
        .value(U256::from(CHECKIN_VALUE));
    client.call(&tx.into(), None).await.is_ok()
}

fn hex_to_bytes(hex: &str) -> Vec<u8> {
    let hex = hex.trim_start_matches("0x");
    (0..hex.len())
        .step_by(2)
        .map(|i| u8::from_str_radix(&hex[i..i + 2], 16).unwrap_or(0))
        .collect()
}

async fn create_contract_tx(
    client: &Client,
    nonce: U256,
    data: ethers::types::Bytes,
    value: U256,
    gas_fallback: u64,
    title: &str,
) -> Result<U256> {
    use ethers::types::{Eip1559TransactionRequest, TransactionRequest};
    use ethers::types::transaction::eip2718::TypedTransaction;
    use ethers::providers::Middleware;
    use crate::constants::CHAIN_ID;

    ly(&format!("{} transaction is now starting", title));

    let from = client.address();
    let fee = get_fee_params(client).await;

    // Estimate gas for contract creation (no 'to' field)
    let gas = {
        let tx = TransactionRequest::new()
            .from(from)
            .nonce(nonce)
            .data(data.clone())
            .value(value);
        let typed: TypedTransaction = tx.into();
        match client.estimate_gas(&typed, None).await {
            Ok(g) => (g * U256::from(12) / U256::from(10) + U256::from(5000)).as_u64(),
            Err(_) => gas_fallback,
        }
    };

    let tx: TypedTransaction = if fee.eip1559 {
        Eip1559TransactionRequest::new()
            .from(from)
            .nonce(nonce)
            .data(data)
            .value(value)
            .gas(gas)
            .max_fee_per_gas(fee.max_fee)
            .max_priority_fee_per_gas(fee.priority_fee)
            .chain_id(CHAIN_ID)
            .into()
    } else {
        TransactionRequest::new()
            .from(from)
            .nonce(nonce)
            .data(data)
            .value(value)
            .gas(gas)
            .gas_price(fee.gas_price)
            .chain_id(CHAIN_ID)
            .into()
    };

    let pending = client
        .send_transaction(tx, None)
        .await
        .map_err(|e| anyhow::anyhow!("Transaction broadcast failed: {}", e))?;

    let tx_hash = pending.tx_hash();
    lg("Transaction broadcast completed successfully");
    lg(&format!("Transaction hash {:x}", tx_hash));

    let rcpt = wait_receipt(client, tx_hash).await?;
    let status = rcpt.status.map(|s| s.as_u64()).unwrap_or(0);

    if status == 1 {
        lg("Receipt confirmed with successful execution");
    } else {
        lr("Receipt confirmed with failed execution");
        anyhow::bail!("Transaction execution failed");
    }

    Ok(nonce + 1)
}

fn build_simple_deploy(fee_receiver: Address) -> ethers::types::Bytes {
    use ethers::abi::{encode, Token};
    let value = U256::from(CHECKIN_VALUE);
    let mut data = hex_to_bytes(SIMPLE_BYTECODE);
    let args = encode(&[Token::Address(fee_receiver), Token::Uint(value)]);
    data.extend_from_slice(&args);
    ethers::types::Bytes::from(data)
}

fn build_erc20_deploy(fee_receiver: Address) -> ethers::types::Bytes {
    use ethers::abi::{encode, Token};
    let supply: U256 = U256::from_dec_str("1000000000000000000000000").unwrap();
    let value = U256::from(CHECKIN_VALUE);
    let mut data = hex_to_bytes(ERC20_BYTECODE);
    let args = encode(&[
        Token::String("Chainstreak Token".to_string()),
        Token::String("CST".to_string()),
        Token::Uint(supply),
        Token::Address(fee_receiver),
        Token::Uint(value),
    ]);
    data.extend_from_slice(&args);
    ethers::types::Bytes::from(data)
}

fn build_erc721_deploy(fee_receiver: Address) -> ethers::types::Bytes {
    use ethers::abi::{encode, Token};
    let value = U256::from(CHECKIN_VALUE);
    let mut data = hex_to_bytes(ERC721_BYTECODE);
    let args = encode(&[
        Token::String("Chainstreak NFT".to_string()),
        Token::String("CSNFT".to_string()),
        Token::Uint(U256::from(1u64)),
        Token::Address(fee_receiver),
        Token::Uint(value),
    ]);
    data.extend_from_slice(&args);
    ethers::types::Bytes::from(data)
}


pub async fn run(client: &Client, mut nonce: U256) -> Result<U256> {
    ly("Chainstreak category execution started");

    let fee_receiver = Address::from_str(FEE_RECEIVER).unwrap();
    let checkin_contract = Address::from_str(CHECKIN_CONTRACT).unwrap();
    let value = U256::from(CHECKIN_VALUE);

    if can_checkin_onchain(client).await {
        match execute_tx(
            client, nonce, checkin_contract,
            calldata::build_checkin(),
            value, 200000,
            "Chainstreak Check In Onchain",
        ).await {
            Ok(n) => { nonce = n; lg("Chainstreak onchain check in completed"); }
            Err(e) => lr(&format!("Chainstreak Check In Onchain failed: {}", e)),
        }
        nonce = refresh_nonce(client, nonce).await;
    } else {
        ly("Chainstreak onchain check in already done today, skipping");
    }

    match create_contract_tx(
        client, nonce,
        build_simple_deploy(fee_receiver),
        value, 500000,
        "Chainstreak Deploy Simple Contract",
    ).await {
        Ok(n) => { nonce = n; lg("Chainstreak simple contract deployed"); }
        Err(e) => lr(&format!("Chainstreak Deploy Simple Contract failed: {}", e)),
    }
    nonce = refresh_nonce(client, nonce).await;

    match create_contract_tx(
        client, nonce,
        build_erc20_deploy(fee_receiver),
        value, 1000000,
        "Chainstreak Deploy ERC-20",
    ).await {
        Ok(n) => { nonce = n; lg("Chainstreak ERC-20 deployed"); }
        Err(e) => lr(&format!("Chainstreak Deploy ERC-20 failed: {}", e)),
    }
    nonce = refresh_nonce(client, nonce).await;

    match create_contract_tx(
        client, nonce,
        build_erc721_deploy(fee_receiver),
        value, 1500000,
        "Chainstreak Deploy ERC-721",
    ).await {
        Ok(n) => { nonce = n; lg("Chainstreak ERC-721 deployed"); }
        Err(e) => lr(&format!("Chainstreak Deploy ERC-721 failed: {}", e)),
    }
    nonce = refresh_nonce(client, nonce).await;

    lg("Chainstreak category execution completed");
    Ok(nonce)
}